import { useState, useRef, useEffect } from "react";

export interface UseAudioPlaybackOptions {
  onPlay?: () => void;
  onPause?: () => void;
  onEnd?: () => void;
  onError?: (error: Error) => void;
}

export interface UseAudioPlaybackReturn {
  isPlaying: boolean;
  audioUrl: string;
  playbackTime: number;
  duration: number;
  audioLoaded: boolean;
  audioRef: React.RefObject<HTMLAudioElement | null>;
  togglePlayback: () => Promise<void>;
  stop: () => void;
  seek: (time: number) => void;
  setPlaybackRate: (rate: number) => void;
  resetAudio: () => void;
}

export const useAudioPlayback = (
  source: File | Blob | string | null,
  options?: UseAudioPlaybackOptions
): UseAudioPlaybackReturn => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string>("");
  const [playbackTime, setPlaybackTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [audioLoaded, setAudioLoaded] = useState(false);

  const audioRef = useRef<HTMLAudioElement>(null);
  const animationRef = useRef<number | null>(null);
  const objectUrlRef = useRef<string | null>(null);

  // Update audio URL when source changes
  useEffect(() => {
    // Clean up previous object URL
    if (objectUrlRef.current) {
      URL.revokeObjectURL(objectUrlRef.current);
      objectUrlRef.current = null;
    }

    // eslint-disable-next-line react-hooks/set-state-in-effect
    setAudioLoaded(false);
    setDuration(0);
    setPlaybackTime(0);
    setIsPlaying(false);

    if (source instanceof File || source instanceof Blob) {
      const url = URL.createObjectURL(source);
      objectUrlRef.current = url;
      setAudioUrl(url);
    } else if (typeof source === "string") {
      setAudioUrl(source);
    } else {
      setAudioUrl("");
    }
  }, [source]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
      if (objectUrlRef.current) {
        URL.revokeObjectURL(objectUrlRef.current);
      }
    };
  }, []);

  const updatePlaybackTime = () => {
    if (audioRef.current && isPlaying && !audioRef.current.paused) {
      setPlaybackTime(audioRef.current.currentTime);
      animationRef.current = requestAnimationFrame(updatePlaybackTime);
    }
  };

  const togglePlayback = async () => {
    if (!audioRef.current || !audioLoaded) return;

    try {
      if (isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
        if (animationRef.current) {
          cancelAnimationFrame(animationRef.current);
          animationRef.current = null;
        }
        options?.onPause?.();
      } else {
        await audioRef.current.play();
        setIsPlaying(true);
        updatePlaybackTime();
        options?.onPlay?.();
      }
    } catch (error) {
      console.error("Error playing audio:", error);
      setIsPlaying(false);
      options?.onError?.(error as Error);
    }
  };

  const stop = () => {
    if (!audioRef.current) return;

    audioRef.current.pause();
    audioRef.current.currentTime = 0;
    setIsPlaying(false);
    setPlaybackTime(0);

    if (animationRef.current) {
      cancelAnimationFrame(animationRef.current);
      animationRef.current = null;
    }
  };

  const seek = (time: number) => {
    if (!audioRef.current) return;
    audioRef.current.currentTime = Math.max(0, Math.min(time, duration));
    setPlaybackTime(audioRef.current.currentTime);
  };

  const setPlaybackRate = (rate: number) => {
    if (!audioRef.current) return;
    audioRef.current.playbackRate = rate;
  };

  const resetAudio = () => {
    stop();

    if (objectUrlRef.current) {
      URL.revokeObjectURL(objectUrlRef.current);
      objectUrlRef.current = null;
    }

    setDuration(0);
    setAudioLoaded(false);
    setAudioUrl("");
  };

  // Audio event handlers
  const handleLoadedMetadata = () => {
    if (
      audioRef.current &&
      !isNaN(audioRef.current.duration) &&
      isFinite(audioRef.current.duration)
    ) {
      setDuration(audioRef.current.duration);
      setAudioLoaded(true);
    }
  };

  const handleCanPlay = () => {
    if (
      audioRef.current &&
      !isNaN(audioRef.current.duration) &&
      isFinite(audioRef.current.duration)
    ) {
      setDuration(audioRef.current.duration);
      setAudioLoaded(true);
    }
  };

  const handleTimeUpdate = () => {
    if (audioRef.current && isPlaying) {
      setPlaybackTime(audioRef.current.currentTime);
    }
  };

  const handleEnded = () => {
    setIsPlaying(false);
    setPlaybackTime(0);
    if (animationRef.current) {
      cancelAnimationFrame(animationRef.current);
      animationRef.current = null;
    }
    if (audioRef.current) {
      audioRef.current.currentTime = 0;
    }
    options?.onEnd?.();
  };

  const handleError = (e: React.SyntheticEvent<HTMLAudioElement>) => {
    console.error("Audio error:", e);
    setAudioLoaded(false);
    setIsPlaying(false);
    options?.onError?.(new Error("Error loading audio file"));
  };

  // Attach event handlers
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    audio.addEventListener("loadedmetadata", handleLoadedMetadata);
    audio.addEventListener("canplay", handleCanPlay);
    audio.addEventListener("timeupdate", handleTimeUpdate);
    audio.addEventListener("ended", handleEnded);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    audio.addEventListener("error", handleError as any);

    return () => {
      audio.removeEventListener("loadedmetadata", handleLoadedMetadata);
      audio.removeEventListener("canplay", handleCanPlay);
      audio.removeEventListener("timeupdate", handleTimeUpdate);
      audio.removeEventListener("ended", handleEnded);
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      audio.removeEventListener("error", handleError as any);
    };
  }, [isPlaying, options]);

  return {
    isPlaying,
    audioUrl,
    playbackTime,
    duration,
    audioLoaded,
    audioRef,
    togglePlayback,
    stop,
    seek,
    setPlaybackRate,
    resetAudio,
  };
};

import { useEffect, useRef, useState } from "react";
import type WaveSurfer from "wavesurfer.js";

export interface UseAudioWaveformOptions {
  waveColor?: string;
  progressColor?: string;
  height?: number;
  barWidth?: number;
  barGap?: number;
  barRadius?: number;
  normalize?: boolean;
  onPlay?: () => void;
  onPause?: () => void;
  onEnd?: () => void;
  onError?: (error: Error) => void;
  onReady?: () => void;
}

export interface UseAudioWaveformReturn {
  waveformRef: React.RefObject<HTMLDivElement | null>;
  isPlaying: boolean;
  isLoading: boolean;
  duration: number;
  currentTime: number;
  playPause: () => void;
  stop: () => void;
  seek: (time: number) => void;
  setPlaybackRate: (rate: number) => void;
}

export const useAudioWaveform = (
  audioUrl: string | null,
  options: UseAudioWaveformOptions = {}
): UseAudioWaveformReturn => {
  const {
    waveColor = "#e5e7eb",
    progressColor = "#3b82f6",
    height = 64,
    barWidth = 4,
    barGap = 8,
    barRadius = 30,
    normalize = true,
    onPlay,
    onPause,
    onEnd,
    onError,
    onReady,
  } = options;

  const waveformRef = useRef<HTMLDivElement>(null);
  const wavesurferRef = useRef<WaveSurfer | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);

  useEffect(() => {
    if (!waveformRef.current || !audioUrl) return;

    let wavesurfer: WaveSurfer | null = null;

    // Dynamic import of WaveSurfer
    import("wavesurfer.js").then((WaveSurferModule) => {
      const WaveSurfer = WaveSurferModule.default;

      if (!waveformRef.current) return;

      wavesurfer = WaveSurfer.create({
        container: waveformRef.current,
        waveColor,
        progressColor,
        height,
        barWidth,
        barGap,
        barRadius,
        cursorWidth: 2,
        cursorColor: progressColor,
        normalize,
        backend: "WebAudio",
        mediaControls: false,
      });

      wavesurferRef.current = wavesurfer;

      // Load audio
      wavesurfer.load(audioUrl);

      // Event listeners
      wavesurfer.on("ready", () => {
        setIsLoading(false);
        setDuration(wavesurfer!.getDuration());
        onReady?.();
      });

      wavesurfer.on("play", () => {
        setIsPlaying(true);
        onPlay?.();
      });

      wavesurfer.on("pause", () => {
        setIsPlaying(false);
        onPause?.();
      });

      wavesurfer.on("finish", () => {
        setIsPlaying(false);
        setCurrentTime(0);
        onEnd?.();
      });

      wavesurfer.on("audioprocess", () => {
        setCurrentTime(wavesurfer!.getCurrentTime());
      });

      wavesurfer.on("seeking", () => {
        setCurrentTime(wavesurfer!.getCurrentTime());
      });

      wavesurfer.on("error", (error) => {
        console.error("WaveSurfer error:", error);
        setIsLoading(false);
        onError?.(new Error(String(error)));
      });
    });

    // Cleanup
    return () => {
      if (wavesurfer) {
        wavesurfer.destroy();
      }
      wavesurferRef.current = null;
    };
  }, [
    audioUrl,
    waveColor,
    progressColor,
    height,
    barWidth,
    barGap,
    barRadius,
    normalize,
  ]);

  const playPause = () => {
    if (wavesurferRef.current) {
      wavesurferRef.current.playPause();
    }
  };

  const stop = () => {
    if (wavesurferRef.current) {
      wavesurferRef.current.stop();
      setCurrentTime(0);
    }
  };

  const seek = (time: number) => {
    if (wavesurferRef.current && duration > 0) {
      const seekPosition = Math.max(0, Math.min(time / duration, 1));
      wavesurferRef.current.seekTo(seekPosition);
    }
  };

  const setPlaybackRate = (rate: number) => {
    if (wavesurferRef.current) {
      wavesurferRef.current.setPlaybackRate(rate);
    }
  };

  return {
    waveformRef,
    isPlaying,
    isLoading,
    duration,
    currentTime,
    playPause,
    stop,
    seek,
    setPlaybackRate,
  };
};
